using Microsoft.JSInterop;

namespace sv_104047f5c1e54b40b9b4b6dd992485f6.Components.Pages;

public sealed class NotepadInterop : IAsyncDisposable
{
    internal const string ModulePath = "./Components/Pages/Notepad.razor.js";
    internal const string InitMethod = "initialize";
    internal const string SaveMethod = "save";
    internal const string ClearMethod = "clear";
    internal const string DisposeMethod = "dispose";

    private readonly IJSRuntime _js;
    private IJSObjectReference? _module;

    public NotepadInterop(IJSRuntime js) => _js = js;

    private async ValueTask<IJSObjectReference> GetModuleAsync()
        => _module ??= await _js.InvokeAsync<IJSObjectReference>("import", ModulePath);

    /// <summary>
    /// Loads saved content from localStorage and registers the beforeunload listener.
    /// Returns the previously saved text, or null if nothing was stored.
    /// </summary>
    public async ValueTask<string?> InitializeAsync(DotNetObjectReference<Notepad> dotNetRef)
    {
        var module = await GetModuleAsync();
        return await module.InvokeAsync<string?>(InitMethod, dotNetRef);
    }

    /// <summary>
    /// Persists the current text to localStorage and marks content as clean.
    /// </summary>
    public async ValueTask SaveAsync(string content)
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync(SaveMethod, content);
    }

    /// <summary>
    /// Removes the stored content from localStorage and marks content as clean.
    /// </summary>
    public async ValueTask ClearAsync()
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync(ClearMethod);
    }

    public async ValueTask DisposeAsync()
    {
        try
        {
            if (_module is not null)
            {
                await _module.InvokeVoidAsync(DisposeMethod);
                await _module.DisposeAsync();
            }
        }
        catch (JSDisconnectedException) { }
    }
}

const STORAGE_KEY = 'notepad-content';
const ON_AUTOSAVE = 'OnAutoSave';

let dotNetRef = null;
let isDirty = false;

function beforeUnloadHandler(e) {
    if (isDirty) {
        e.preventDefault();
    }
}

export function initialize(ref) {
    dotNetRef = ref;
    window.addEventListener('beforeunload', beforeUnloadHandler);
    return localStorage.getItem(STORAGE_KEY);
}

export function save(content) {
    localStorage.setItem(STORAGE_KEY, content);
    isDirty = false;
}

export function clear() {
    localStorage.removeItem(STORAGE_KEY);
    isDirty = false;
}

export function dispose() {
    window.removeEventListener('beforeunload', beforeUnloadHandler);
    dotNetRef = null;
    isDirty = false;
}

// Called from .NET when content changes to track dirty state
export function markDirty() {
    isDirty = true;
}

