@page "/notepad"
@inject IJSRuntime JS
@implements IAsyncDisposable

<PageTitle>Notepad</PageTitle>

<h1>Notepad</h1>

<textarea class="form-control mb-3" rows="12" @bind="Content" @bind:event="oninput"
          @bind:after="OnContentChanged" placeholder="Type your notes here…"></textarea>

<div class="d-flex align-items-center gap-2 mb-3">
    <button class="btn btn-primary" @onclick="SaveNowAsync">Save now</button>
    <button class="btn btn-danger" @onclick="ClearAsync">Clear</button>
    @if (_lastSaved is not null)
    {
        <span class="text-muted">Last saved at @_lastSaved.Value.ToString("HH:mm:ss")</span>
    }
</div>

@code {
    private string Content { get; set; } = string.Empty;
    private DateTime? _lastSaved;
    private NotepadInterop? _interop;
    private DotNetObjectReference<Notepad>? _dotNetRef;
    private Timer? _autoSaveTimer;
    private bool _isDirty;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _interop = new NotepadInterop(JS);
            _dotNetRef = DotNetObjectReference.Create(this);

            var saved = await _interop.InitializeAsync(_dotNetRef);
            if (!string.IsNullOrEmpty(saved))
            {
                Content = saved;
                StateHasChanged();
            }

            _autoSaveTimer = new Timer(AutoSaveCallback, null, TimeSpan.FromSeconds(30), TimeSpan.FromSeconds(30));
        }
    }

    private async void OnContentChanged()
    {
        _isDirty = true;
        if (_interop is not null)
        {
            var module = await JS.InvokeAsync<IJSObjectReference>("import", NotepadInterop.ModulePath);
            await module.InvokeVoidAsync("markDirty");
            await module.DisposeAsync();
        }
    }

    private async void AutoSaveCallback(object? state)
    {
        if (_isDirty && _interop is not null)
        {
            await InvokeAsync(async () =>
            {
                try
                {
                    await _interop.SaveAsync(Content);
                    _isDirty = false;
                    _lastSaved = DateTime.Now;
                    StateHasChanged();
                }
                catch (JSDisconnectedException) { }
            });
        }
    }

    private async Task SaveNowAsync()
    {
        if (_interop is not null)
        {
            await _interop.SaveAsync(Content);
            _isDirty = false;
            _lastSaved = DateTime.Now;
        }
    }

    private async Task ClearAsync()
    {
        if (_interop is not null)
        {
            await _interop.ClearAsync();
            Content = string.Empty;
            _isDirty = false;
            _lastSaved = null;
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_autoSaveTimer is not null)
        {
            await _autoSaveTimer.DisposeAsync();
        }

        if (_interop is not null)
        {
            await _interop.DisposeAsync();
        }

        _dotNetRef?.Dispose();
    }
}

